.conteneur {
  display: flex;              /* active flexbox */
  flex-direction: row;        /* direction : row (défaut) ou column */
  justify-content: center;    /* alignement sur l'axe principal */
  align-items: center;        /* alignement sur l'axe secondaire */
  gap: 16px;                  /* espace entre les éléments */
  flex-wrap: wrap;            /* retour à la ligne si nécessaire */
}

/* Les enfants directs deviennent des flex items */
.item {
  flex: 1;                    /* prend autant d'espace que possible */
}

.item-fixe {
  flex: 0 0 200px;            /* largeur fixe de 200px, ne grandit pas */
}

/* Centrer parfaitement un élément */
.centrer-tout {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
}
